			console.log('Botão de impressão clicado, ID do pedido:', el.getAttribute('data-manage-order-id'));
			e.preventDefault();
			e.stopImmediatePropagation();

			// Coletar dados do pedido via API para impressão no Electron
			var orderId = el.getAttribute('data-manage-order-id');
